import React, { useState } from 'react';
import { 
  PhoneMissed, 
  User, 
  Tag, 
  Mail, 
  Flag, 
  MessageSquare, 
  Search, 
  FileAudio,
  FileText,
  Monitor,
  Hash,
  Bot,
  ArrowUpRight,
  ArrowDownLeft,
  CheckCheck,
  ListOrdered,
  Timer,
  BrainCircuit,
  Activity,
  Mic,
  MessageCircle,
  Smile,
  Meh,
  Frown,
  OctagonAlert
} from 'lucide-react';
import { MOCK_CALLS } from '../constants';
import { CallRecord } from '../types';

export const ActivityLog: React.FC = () => {
  // State to toggle between List View and Detail View
  const [view, setView] = useState<'list' | 'detail'>('list');
  const [selectedItem, setSelectedItem] = useState<CallRecord | null>(null);

  const handleItemClick = (item: CallRecord) => {
    setSelectedItem(item);
    setView('detail');
  };

  const handleBack = () => {
    setView('list');
    setSelectedItem(null);
  };

  // Render the appropriate view
  if (view === 'detail' && selectedItem) {
      return <DetailView onBack={handleBack} contactName={selectedItem.contactName} />;
  }

  return (
    <div className="bg-white rounded-lg shadow-sm border border-slate-300 overflow-hidden flex flex-col h-full font-sans relative">

      {/* LIST VIEW HEADER */}
      <div className="p-2 border-b border-slate-300 flex gap-2 bg-slate-50 items-center flex-shrink-0">
        <div className="relative flex-1">
          <input 
            type="text" 
            className="w-full border border-slate-300 rounded px-2 py-1 text-xs focus:outline-none focus:border-emerald-600 focus:ring-1 focus:ring-emerald-500/20 bg-white placeholder-slate-400 pl-7"
            placeholder="Search history..." 
          />
          <Search className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400" size={12} />
        </div>
        <button className="p-1 text-slate-400 hover:text-slate-600" title="Filter">
            <ListOrdered size={14} />
        </button>
      </div>

      {/* Date Header */}
      <div className="px-3 py-1 border-b-2 border-rose-500 bg-slate-100 flex justify-between items-center shadow-sm relative z-10 flex-shrink-0">
        <span className="text-[11px] font-bold text-rose-600 uppercase tracking-wide">19/11/2025 ({MOCK_CALLS.length})</span>
        <span className="text-[10px] font-bold text-slate-500 uppercase">Today</span>
      </div>

      {/* Main List */}
      <div className="overflow-y-auto flex-1 scrollbar-thin bg-slate-50/50 relative">
        {MOCK_CALLS.map((call, idx) => (
          <div key={call.id} onClick={() => handleItemClick(call)} className="cursor-pointer">
              <ActivityItem item={call} isEven={idx % 2 === 0} />
          </div>
        ))}
      </div>
    </div>
  );
};

// --- RICH DETAIL VIEW (Simplified for context) ---
const DetailView: React.FC<{ onBack: () => void, contactName: string }> = ({ onBack, contactName }) => {
    return (
        <div className="flex flex-col h-full bg-slate-50 rounded-lg shadow-sm border border-slate-300 overflow-hidden relative">
           <div className="p-4 flex items-center gap-2 border-b border-slate-200 bg-white">
               <button onClick={onBack} className="p-1 hover:bg-slate-100 rounded"><ArrowDownLeft className="rotate-45" size={20}/></button>
               <span className="font-bold text-slate-700">{contactName}</span>
           </div>
           <div className="flex-1 p-4 flex items-center justify-center text-slate-400 text-sm">
               Chat details would go here...
           </div>
        </div>
    );
}

// --- LIST VIEW ITEM ---
const ActivityItem: React.FC<{ item: CallRecord, isEven: boolean }> = ({ item, isEven }) => {
  const [hoverPos, setHoverPos] = useState({ x: 0, y: 0 });
  const [hoverType, setHoverType] = useState<'summary' | 'emotion' | null>(null);

  const handleMouseMove = (e: React.MouseEvent) => {
    requestAnimationFrame(() => {
        setHoverPos({ x: e.clientX, y: e.clientY });
    });
  };

  const getSentimentColor = () => {
    switch (item.flags.sentiment) {
      case 'positive': return 'bg-emerald-500';
      case 'negative': return 'bg-amber-500';
      case 'angry': return 'bg-rose-600';
      default: return 'bg-slate-300';
    }
  };

  const getDirectionIcon = () => {
    if (item.type === 'message') {
        return item.direction === 'inbound' 
            ? <MessageSquare size={13} className="text-indigo-600 fill-indigo-50" /> 
            : <MessageSquare size={13} className="text-slate-400" />;
    }
    switch (item.direction) {
      case 'inbound': return <ArrowDownLeft size={14} strokeWidth={2.5} className="text-emerald-600" />;
      case 'outbound': return <ArrowUpRight size={14} strokeWidth={2.5} className="text-blue-600" />;
      case 'missed': return <PhoneMissed size={14} strokeWidth={2.5} className="text-rose-600" />;
    }
  };

  return (
    <div 
        className={`group relative py-1.5 border-b border-slate-200 flex items-center text-[11px] hover:bg-blue-50/50 transition-colors ${isEven ? 'bg-white' : 'bg-slate-50/30'}`}
        onMouseMove={handleMouseMove}
    >
      {/* Sentiment Indicator (Left Border) */}
      <div className={`absolute left-0 top-0 bottom-0 w-[3px] ${getSentimentColor()} opacity-80`}></div>

      {/* Time */}
      <div className="w-[72px] pl-3 font-medium text-slate-600 tabular-nums tracking-tight whitespace-nowrap flex-shrink-0">
        {item.timestamp}
      </div>

      {/* Source Icon */}
      <div className="w-8 flex justify-center text-slate-400 flex-shrink-0">
          {item.isBot ? <Bot size={16} className="text-emerald-600" /> : <Monitor size={14} strokeWidth={1.5} />}
      </div>

      {/* Contact Info */}
      <div 
        className="flex-1 min-w-0 flex flex-col justify-center px-1 cursor-help"
        onMouseEnter={() => setHoverType('summary')}
        onMouseLeave={() => setHoverType(null)}
      >
        <div className={`font-bold truncate leading-tight ${item.isBot ? 'text-emerald-700' : 'text-slate-700'}`}>{item.contactName}</div>
        <div className="flex items-center gap-1 text-[9px] text-slate-400 leading-none mt-0.5 truncate">
           <User size={9} /><span className="font-medium">{item.contactId}</span>
        </div>
      </div>

      {/* Phone / ID Info */}
      <div className="w-24 flex-col justify-center px-1 border-l border-slate-100/50 flex-shrink-0 hidden 2xl:flex">
        <div className="font-semibold text-slate-600 truncate leading-tight flex items-center gap-1 tabular-nums tracking-tight">{item.phoneNumber}</div>
        <div className="flex items-center gap-1 text-[9px] text-slate-400 leading-none mt-0.5">
           <Hash size={9} /><span className="font-medium tabular-nums">{item.callId}</span>
        </div>
      </div>

       {/* NEW HOLLOW SENTIMENT BADGE */}
       <div 
         className="w-[40px] flex justify-center items-center flex-shrink-0 cursor-help"
         onMouseEnter={() => setHoverType('emotion')}
         onMouseLeave={() => setHoverType(null)}
        >
             {item.flags.sentiment && !item.isBot && (
                 <HollowSentimentIcon sentiment={item.flags.sentiment} />
             )}
             {item.isBot && (
                <Bot size={16} className="text-emerald-500 opacity-80" />
             )}
        </div>

      {/* Flags Section */}
      <div className="flex items-center justify-end gap-2 px-2 flex-shrink-0">
        <div className="flex items-center gap-1.5 opacity-70 hover:opacity-100 transition-opacity hidden sm:flex">
            <IconWrapper active={item.flags.recorded} icon={FileAudio} title="Recorded" color="text-emerald-600" />
            <IconWrapper active={item.flags.hasNotes} icon={Tag} title="Notes" color="text-emerald-600" />
            <IconWrapper active={item.flags.verified} icon={FileText} title="Verified" color="text-emerald-600" />
            <IconWrapper active={item.flags.hasEmail} icon={Mail} title="Email" color="text-emerald-600" />
            <IconWrapper active={item.flags.hasCrm} icon={Flag} title="CRM" color="text-amber-600" />
        </div>
        {item.country && (
            <span className="font-mono text-[9px] font-bold text-slate-400 bg-slate-100 px-1 rounded border border-slate-200">
                {item.country}
            </span>
        )}
      </div>

      {/* Duration & Icon */}
      <div className="w-14 text-right font-bold text-slate-600 tabular-nums tracking-tight flex-shrink-0">{item.duration}</div>
      <div className="w-8 flex justify-center pl-1 flex-shrink-0">{getDirectionIcon()}</div>

      {/* --- MOUSE FOLLOWER TOOLTIPS --- */}

      {/* 1. VISUAL SUMMARY (Vertical Card) */}
      {item.summary && hoverType === 'summary' && (
        <div 
            style={{ 
                top: Math.min(window.innerHeight - 450, hoverPos.y + 10), 
                left: Math.min(window.innerWidth - 340, hoverPos.x + 15) 
            }}
            className="fixed z-[9999] w-[320px] bg-white/60 backdrop-blur-2xl text-slate-800 rounded-3xl shadow-[0_25px_50px_rgba(0,0,0,0.15)] border border-white/60 animate-in fade-in zoom-in-95 duration-200 pointer-events-none ring-1 ring-white/50 overflow-hidden flex flex-col"
        >
             <div className="relative h-48 w-full bg-slate-100 overflow-hidden flex-shrink-0">
                <img 
                    src={item.generatedImageUrl || "https://images.unsplash.com/photo-1551288049-bebda4e38f71?q=80&w=800&auto=format&fit=crop"} 
                    alt="AI Generated"
                    className="w-full h-full object-cover"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-white via-transparent to-black/20"></div>
                 <div className="absolute bottom-2 left-2 right-2">
                     <div className="flex items-center gap-2">
                        <div className="w-6 h-6 rounded-full bg-indigo-600 flex items-center justify-center shadow-lg border-2 border-white">
                            <BrainCircuit size={12} className="text-white" />
                        </div>
                        <span className="text-[10px] font-black text-slate-800 uppercase tracking-wide bg-white/90 px-2 py-0.5 rounded backdrop-blur shadow-sm">AI Summary</span>
                     </div>
                 </div>
             </div>

             <div className="p-4 bg-white/40 max-h-[50vh] overflow-y-auto scrollbar-thin">
                 <div className="mb-4">
                     <p className="text-xs leading-relaxed text-slate-800 font-medium">{item.summary}</p>
                 </div>
                 <div className="grid grid-cols-2 gap-2 mb-2">
                     <div className="bg-white/50 border border-slate-100 rounded-lg p-2 flex items-center gap-2">
                         <div className="p-1.5 bg-emerald-100 text-emerald-600 rounded"><CheckCheck size={12}/></div>
                         <div className="flex flex-col leading-none">
                             <span className="text-[8px] text-slate-400 font-bold uppercase">Confidence</span>
                             <span className="text-xs font-bold text-slate-700">98.5%</span>
                         </div>
                     </div>
                      <div className="bg-white/50 border border-slate-100 rounded-lg p-2 flex items-center gap-2">
                         <div className="p-1.5 bg-blue-100 text-blue-600 rounded"><Timer size={12}/></div>
                         <div className="flex flex-col leading-none">
                             <span className="text-[8px] text-slate-400 font-bold uppercase">Time</span>
                             <span className="text-xs font-bold text-slate-700">0.4s</span>
                         </div>
                     </div>
                 </div>
             </div>
        </div>
      )}

      {/* 2. SENTIMENT ANALYSIS */}
      {hoverType === 'emotion' && (
        <div 
             style={{ 
                top: Math.min(window.innerHeight - 200, hoverPos.y + 15), 
                left: Math.min(window.innerWidth - 300, hoverPos.x - 140)
            }}
            className="fixed z-[9999] w-[280px] bg-white/70 backdrop-blur-3xl text-slate-800 p-3 rounded-2xl shadow-[0_15px_40px_rgba(0,0,0,0.15)] border border-white/60 animate-in fade-in zoom-in-95 duration-200 pointer-events-none ring-1 ring-white/50"
        >
            <div className="flex items-center gap-2 mb-3 pb-2 border-b border-slate-200/50">
                <Activity size={16} className="text-rose-500" />
                <span className="text-xs font-black text-slate-800 uppercase tracking-wide">Emotion Analysis</span>
            </div>

            <div className="grid gap-3">
                <div className="bg-white/50 rounded-xl p-2.5 border border-white/50">
                     <div className="flex items-center gap-1.5 mb-1.5">
                        <Mic size={12} className="text-slate-500" />
                        <span className="text-[10px] font-bold text-slate-600 uppercase">Vocal Metrics</span>
                     </div>
                     <div className="flex gap-1 flex-wrap">
                        <span className="text-[9px] px-1.5 py-0.5 bg-rose-50 text-rose-700 rounded border border-rose-100 font-medium">Pitch: High</span>
                        <span className="text-[9px] px-1.5 py-0.5 bg-orange-50 text-orange-700 rounded border border-orange-100 font-medium">Speed: Fast</span>
                        <span className="text-[9px] px-1.5 py-0.5 bg-slate-100 text-slate-600 rounded border border-slate-200 font-medium">Jitter: 12%</span>
                     </div>
                </div>
                <div className="bg-white/50 rounded-xl p-2.5 border border-white/50">
                     <div className="flex items-center gap-1.5 mb-1.5">
                        <MessageCircle size={12} className="text-slate-500" />
                        <span className="text-[10px] font-bold text-slate-600 uppercase">Semantic Context</span>
                     </div>
                     <p className="text-[10px] leading-snug text-slate-700 font-medium">
                        {item.sentimentReason || "No specific context available."}
                     </p>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

// --- NEW HOLLOW SENTIMENT ICONS ---
const HollowSentimentIcon: React.FC<{ sentiment: string }> = ({ sentiment }) => {
    switch(sentiment) {
        case 'positive': 
            return <Smile size={20} strokeWidth={2} className="text-emerald-500" />;
        case 'negative': 
            return <Frown size={20} strokeWidth={2} className="text-amber-500" />;
        case 'angry': 
            return <OctagonAlert size={20} strokeWidth={2} className="text-rose-600" />;
        default: 
            return <Meh size={20} strokeWidth={2} className="text-slate-400" />;
    }
}

const IconWrapper: React.FC<{ active: boolean, icon: React.ElementType, color?: string, title?: string }> = ({ active, icon: Icon, color, title }) => {
    if (!active) return <div className="w-3 h-3"></div>;
    return <div className={`w-3 h-3 ${color || 'text-slate-500'}`} title={title}><Icon size={12} strokeWidth={2.5} /></div>
}

import React, { useState, useEffect, useRef } from 'react';
import { ChevronDown, Cloud, Power, Wifi, RefreshCw, Square } from 'lucide-react';

// Define the exact statuses with text colors for the dropdown icons
const USER_STATUSES = [
  { label: 'Available', color: 'bg-emerald-500', textColor: 'text-emerald-500', border: 'border-emerald-600', hover: 'hover:bg-emerald-600', type: 'dot' },
  { label: 'Idle', color: 'bg-slate-500', textColor: 'text-slate-500', border: 'border-slate-600', hover: 'hover:bg-slate-600', type: 'dot' },
  { label: 'Away From Keyboard', color: 'bg-blue-500', textColor: 'text-blue-500', border: 'border-blue-600', hover: 'hover:bg-blue-600', type: 'dot' },
  { label: 'Do Not Disturb', color: 'bg-rose-500', textColor: 'text-rose-500', border: 'border-rose-600', hover: 'hover:bg-rose-600', type: 'dot' },
  { label: 'Out Of Work', color: 'bg-slate-700', textColor: 'text-slate-700', border: 'border-slate-800', hover: 'hover:bg-slate-800', type: 'hollow' }
];

export const Header: React.FC = () => {
  const [time, setTime] = useState(new Date());
  const [isConnected, setIsConnected] = useState(true);

  // Status Dropdown State
  const [statusOpen, setStatusOpen] = useState(false);
  const [currentStatus, setCurrentStatus] = useState(USER_STATUSES[0]);
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setStatusOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      clearInterval(timer);
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const seconds = time.getSeconds();
  const minutes = time.getMinutes();
  const hours = time.getHours();

  return (
    <header className="h-16 bg-white border-b border-slate-300 px-4 flex items-center justify-between flex-shrink-0 shadow-sm z-50 font-sans relative">

      {/* LEFT: Branding & Status Controls */}
      <div className="flex items-center gap-6">
        {/* Logo Placeholder */}
        <div className="flex flex-col leading-none">
            <div className="flex items-center gap-1">
                <div className="w-0 h-0 border-l-[8px] border-l-transparent border-b-[14px] border-b-rose-600 border-r-[8px] border-r-transparent"></div>
                <span className="font-bold text-xl tracking-widest text-slate-800 drop-shadow-sm">TRIDENT</span>
            </div>
            <span className="text-[9px] text-slate-400 tracking-widest pl-4">AI4Groups</span>
        </div>

        {/* Separator */}
        <div className="h-8 w-px bg-slate-300 mx-2"></div>

        {/* Controls */}
        <div className="flex items-center gap-3">
            {/* Extension Badge */}
            <div className="flex flex-col">
                <span className="text-[9px] font-bold text-slate-400 uppercase tracking-wider mb-0.5">Extension</span>
                <button className="px-3 py-1.5 rounded bg-slate-100 border border-slate-300 text-slate-700 font-bold text-xs flex items-center gap-2 shadow-sm tabular-nums hover:bg-slate-200 transition-colors">
                    <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_5px_rgba(16,185,129,0.5)]"></div>
                    89093990236
                </button>
            </div>

            {/* Status Dropdown - SOLID FILL */}
            <div className="flex flex-col relative" ref={dropdownRef}>
                <span className="text-[9px] font-bold text-slate-400 uppercase tracking-wider mb-0.5">My Status</span>
                <button 
                    onClick={() => setStatusOpen(!statusOpen)}
                    className={`px-3 py-1.5 rounded border text-xs font-bold flex items-center gap-2 shadow-sm transition-all min-w-[150px] justify-between text-white ${currentStatus.color} ${currentStatus.border} ${currentStatus.hover}`}
                >
                    <div className="flex items-center gap-2">
                         {/* Icon indicator (White now since background is colored) */}
                         {currentStatus.type === 'dot' ? (
                             <div className="w-2 h-2 rounded-full bg-white shadow-sm"></div>
                         ) : (
                             <div className="w-2 h-2 rounded-sm border-[1.5px] border-white"></div>
                         )}
                         <span className="uppercase tracking-tight text-[11px]">{currentStatus.label === 'Away From Keyboard' ? 'AWAY' : currentStatus.label.toUpperCase()}</span>
                    </div>
                    <ChevronDown size={12} className="text-white/80" />
                </button>

                {/* Dropdown Menu */}
                {statusOpen && (
                    <div className="absolute top-full left-0 mt-2 w-56 bg-white rounded-lg shadow-xl border border-slate-300 py-1 z-[60] animate-in fade-in zoom-in-95 duration-100">
                        {USER_STATUSES.map((status) => (
                            <button
                                key={status.label}
                                onClick={() => {
                                    setCurrentStatus(status);
                                    setStatusOpen(false);
                                }}
                                className="w-full px-4 py-2.5 text-left flex items-center gap-3 hover:bg-slate-50 transition-colors group border-b border-slate-50 last:border-0"
                            >
                                {status.type === 'dot' ? (
                                    <div className={`w-2.5 h-2.5 rounded-full ${status.textColor} bg-current shadow-sm group-hover:scale-110 transition-transform`}></div>
                                ) : (
                                    <div className="w-2.5 h-2.5 rounded-[1px] border-[1.5px] border-slate-600 group-hover:scale-110 transition-transform"></div>
                                )}

                                <span className={`text-xs font-medium ${currentStatus.label === status.label ? 'text-slate-900 font-bold' : 'text-slate-600'}`}>
                                    {status.label}
                                </span>
                            </button>
                        ))}
                    </div>
                )}
            </div>

            {/* Connection Status */}
            <div className="flex flex-col">
                <span className="text-[9px] font-bold text-slate-400 uppercase tracking-wider mb-0.5">WebRTC</span>
                <button 
                    onClick={() => setIsConnected(!isConnected)}
                    className={`px-3 py-1.5 rounded text-[10px] font-bold flex items-center gap-2 shadow-sm border transition-all tabular-nums hover:scale-105 active:scale-95 ${
                        isConnected 
                            ? "bg-emerald-600 border-emerald-700 text-white hover:bg-emerald-700 shadow-emerald-500/20" 
                            : "bg-rose-600 border-rose-700 text-white hover:bg-rose-700 shadow-rose-500/20 animate-pulse"
                    }`}
                    title="Click to toggle connection state (Test)"
                >
                    {isConnected ? (
                        <>
                            <Wifi size={14} strokeWidth={2.5} />
                            <span>CONNECTED: 24ms</span>
                        </>
                    ) : (
                        <>
                            <RefreshCw size={14} className="animate-spin-slow" />
                            <span>RECONNECTING...</span>
                        </>
                    )}
                </button>
            </div>
        </div>
      </div>

      {/* CENTER: Clock (Digital + Analog) */}
      <div className="flex items-center gap-4 pl-8 border-l border-slate-200">
        {/* Analog Clock SVG */}
        <div className="w-10 h-10 relative drop-shadow-md">
            <svg viewBox="0 0 100 100" className="w-full h-full">
                <circle cx="50" cy="50" r="45" fill="white" stroke="#cbd5e1" strokeWidth="3" />
                {[...Array(12)].map((_, i) => (
                    <line 
                        key={i} 
                        x1="50" y1="10" x2="50" y2="15" 
                        stroke="#94a3b8" 
                        strokeWidth="2" 
                        transform={`rotate(${i * 30} 50 50)`} 
                    />
                ))}
                <line 
                    x1="50" y1="50" x2="50" y2="25" 
                    stroke="#475569" 
                    strokeWidth="3" 
                    strokeLinecap="round"
                    transform={`rotate(${(hours % 12) * 30 + minutes * 0.5} 50 50)`} 
                />
                <line 
                    x1="50" y1="50" x2="50" y2="18" 
                    stroke="#64748b" 
                    strokeWidth="2" 
                    strokeLinecap="round"
                    transform={`rotate(${minutes * 6} 50 50)`} 
                />
                <line 
                    x1="50" y1="50" x2="50" y2="15" 
                    stroke="#ef4444" 
                    strokeWidth="1.5" 
                    strokeLinecap="round"
                    transform={`rotate(${seconds * 6} 50 50)`} 
                />
                <circle cx="50" cy="50" r="3" fill="#ef4444" />
            </svg>
        </div>

        <div className="flex flex-col items-start justify-center">
            <div className="text-3xl font-light text-slate-700 tabular-nums tracking-tighter leading-none drop-shadow-sm">
                {time.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
            </div>
            <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">
                {time.toLocaleDateString([], { day: 'numeric', month: 'long', year: 'numeric' })}
            </div>
        </div>
      </div>

      {/* RIGHT: Weather & System Info */}
      <div className="flex items-center gap-6">
        <div className="flex flex-col items-end">
             <span className="text-slate-400 text-[10px] font-black uppercase tracking-widest">Riga, Latvia</span>
             <div className="flex items-center gap-2 text-slate-600">
                <Cloud size={18} className="text-slate-400 fill-slate-100" />
                <span className="text-xl font-light tabular-nums">-4°</span>
             </div>
        </div>

