export const Header: React.FC = () => {
  const [time, setTime] = useState(new Date());
  const [isConnected, setIsConnected] = useState(true);

  // Status Dropdown State
  const [statusOpen, setStatusOpen] = useState(false);
  const [currentStatus, setCurrentStatus] = useState(USER_STATUSES[0]);
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setStatusOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      clearInterval(timer);
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const seconds = time.getSeconds();
  const minutes = time.getMinutes();
  const hours = time.getHours();

  return (
    <header className="h-16 bg-white border-b border-slate-400 px-4 flex items-center justify-between flex-shrink-0 shadow-sm z-50 font-sans relative">

