                      <div className="bg-white/50 border border-slate-200 rounded-lg p-2 flex items-center gap-2">
                         <div className="p-1.5 bg-blue-100 text-blue-600 rounded"><Timer size={12}/></div>
                         <div className="flex flex-col leading-none">
                             <span className="text-[8px] text-slate-400 font-bold uppercase">Time</span>
                             <span className="text-xs font-bold text-slate-700">0.4s</span>
                         </div>
                     </div>
                 </div>
             </div>
        </div>
      )}

      {/* 2. SENTIMENT ANALYSIS */}
      {hoverType === 'emotion' && (
        <div 
             style={{ 
                top: Math.min(window.innerHeight - 200, hoverPos.y + 15), 
                left: Math.min(window.innerWidth - 300, hoverPos.x - 140)
            }}
            className="fixed z-[9999] w-[280px] bg-white/70 backdrop-blur-3xl text-slate-800 p-3 rounded-2xl shadow-[0_15px_40px_rgba(0,0,0,0.15)] border border-white/60 animate-in fade-in zoom-in-95 duration-200 pointer-events-none ring-1 ring-white/50"
        >
            <div className="flex items-center gap-2 mb-3 pb-2 border-b border-slate-200/50">
                <Activity size={16} className="text-rose-500" />
                <span className="text-xs font-black text-slate-800 uppercase tracking-wide">Emotion Analysis</span>
            </div>

            <div className="grid gap-3">
                <div className="bg-white/50 rounded-xl p-2.5 border border-white/50">
                     <div className="flex items-center gap-1.5 mb-1.5">
                        <Mic size={12} className="text-slate-500" />
                        <span className="text-[10px] font-bold text-slate-600 uppercase">Vocal Metrics</span>
                     </div>
                     <div className="flex gap-1 flex-wrap">
                        <span className="text-[9px] px-1.5 py-0.5 bg-rose-50 text-rose-700 rounded border border-rose-100 font-medium">Pitch: High</span>
                        <span className="text-[9px] px-1.5 py-0.5 bg-orange-50 text-orange-700 rounded border border-orange-100 font-medium">Speed: Fast</span>
                        <span className="text-[9px] px-1.5 py-0.5 bg-slate-100 text-slate-600 rounded border border-slate-200 font-medium">Jitter: 12%</span>
                     </div>
                </div>
                <div className="bg-white/50 rounded-xl p-2.5 border border-white/50">
                     <div className="flex items-center gap-1.5 mb-1.5">
                        <MessageCircle size={12} className="text-slate-500" />
                        <span className="text-[10px] font-bold text-slate-600 uppercase">Semantic Context</span>
                     </div>
                     <p className="text-[10px] leading-snug text-slate-700 font-medium">
                        {item.sentimentReason || "No specific context available."}
                     </p>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

// --- NEW HOLLOW SENTIMENT ICONS ---
const HollowSentimentIcon: React.FC<{ sentiment: string }> = ({ sentiment }) => {
    switch(sentiment) {
        case 'positive': 
            return <Smile size={20} strokeWidth={2} className="text-emerald-500" />;
        case 'negative': 
            return <Frown size={20} strokeWidth={2} className="text-amber-500" />;
        case 'angry': 
            return <OctagonAlert size={20} strokeWidth={2} className="text-rose-600" />;
        default: 
            return <Meh size={20} strokeWidth={2} className="text-slate-400" />;
    }
}

const IconWrapper: React.FC<{ active: boolean, icon: React.ElementType, color?: string, title?: string }> = ({ active, icon: Icon, color, title }) => {
    if (!active) return <div className="w-3 h-3"></div>;
    return <div className={`w-3 h-3 ${color || 'text-slate-500'}`} title={title}><Icon size={12} strokeWidth={2.5} /></div>
}

